geo_json_96de9bbbfcaeca98e033069a909977bd.bindTooltip(
function(layer){
let div = L.DomUtil.create('div');
    
let handleObject = feature => {
    if (feature === null) {
        return '';
    } else if (typeof(feature)=='object') {
        return JSON.stringify(feature);
    } else {
        return feature;
    }
}
let fields = ["Name", "Island", "Land_area", "Population", "Median_income", "Sex_ratio"];
let aliases = ["Name", "Island", "Land_area", "Population", "Median_income", "Sex_ratio"];
let table = '<table>' +
    String(
    fields.map(
    (v,i)=>
    `<tr>
        <th>${aliases[i]}</th>
        
        <td>${handleObject(layer.feature.properties[v])}</td>
    </tr>`).join(''))
+'</table>';
div.innerHTML=table;
    
return div
    }
    ,{
  "sticky": true,
  "className": "foliumtooltip",
});
                     
