geo_json_ad093e06d248d3047adce92c8a648442.bindTooltip(
function(layer){
let div = L.DomUtil.create('div');
    
let handleObject = feature => {
    if (feature === null) {
        return '';
    } else if (typeof(feature)=='object') {
        return JSON.stringify(feature);
    } else {
        return feature;
    }
}
let fields = ["t50_fid", "elevation"];
let aliases = ["t50_fid", "elevation"];
let table = '<table>' +
    String(
    fields.map(
    (v,i)=>
    `<tr>
        <th>${aliases[i]}</th>
        
        <td>${handleObject(layer.feature.properties[v])}</td>
    </tr>`).join(''))
+'</table>';
div.innerHTML=table;

return div
}
,{
"sticky": true,
"className": "foliumtooltip",
});
